qry:select.qry:xquery:
for $r in SQL('
SELECT WRK05_ESTRUCTURA.c_role, WRK05_ESTRUCTURA.oi_organigrama FROM WRK05_ESTRUCTURA WHERE WRK05_ESTRUCTURA.oi_estructura = {$FILTER/@PARENT}
')/ROWS/ROW

form:Form.form:Scripts:
		var RS;
var CFG,CHLCFG;
var TIT=null;

//Actualiza la Lista
function LoadList()
{  
  var proxy=GetProxy(); //as NomadProxy
	var param=new NomadXML("DATA");

	param.SetAttr("parent",Ctrl("PARENT").GetXValue());
	param.SetAttr("search",Ctrl("BUSCAR").GetXValue());
	param.SetAttr("order" ,Ctrl("ORDER").GetXValue().substr(1));
	param.SetAttr("asc"   ,Ctrl("ORDER").GetXValue().substr(0,1)=="+"?"1":"0");

  //Cargo el RS
  RS=proxy.SQLService().GetXML(Ctrl("main").getResource("QRY_IDS"), param.ToString());

  //Actualizo el Label
  var total=RS.GetAttrInt("total"); if (isNaN(total)) total=0;
  var count=RS.GetAttrInt("count"); if (isNaN(count)) count=0;
  if (total==count) Ctrl("LIST_REG").SetXValue("Registros: "+total);
               else Ctrl("LIST_REG").SetXValue("Registros: "+count+" de "+total);

  //Genero la Lista de IDS
  var lst=Ctrl("LIST");   

  lst.IDs=new Array();
  for (var cur=RS.FirstChild(); cur!=null; cur=cur.Next())
  	lst.IDs.push(cur.GetAttr("id"));

	lst.ResetSQL();

	///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////                     
	//Lista de Entidades
	{                   
	  var ca=proxy.RPCService();
	  ca.AddParam(new NomadRPCParamOut("OUT", "Nomad.NSystem.Object", "Nomad.NSystem.Proxy.NomadXML"));

	  ca.AddParam(new NomadRPCParam("P1", "IN", "Nomad\\Base\\Login\\Entidades", "String"));
	  ca.AddParam(new NomadRPCParam("P2", "IN", "Nomad.Base.Login.Entidades.ENTIDAD.INFO_REG", "String"));
	  ca.AddParam(new NomadRPCParam("P3", "IN", Ctrl("BUSCAR_2").GetXValue(), "String"));
	  ca.AddParam(new NomadRPCParam("P4", "IN", Ctrl("ORDER_2").GetXValue(), "String"));

	  ca.Execute("Nomad.Base.Report.Listas.INDICE","ListIndex");
	  RS=new NomadXML(ca.GetParam("OUT").Data);
	}   

  //Actualizo el Label
  var total=RS.GetAttrInt("total"); if (isNaN(total)) total=0;
  var count=RS.GetAttrInt("count"); if (isNaN(count)) count=0;
  if (total==count) Ctrl("LIST_REG_2").SetXValue("Registros: "+total);
               else Ctrl("LIST_REG_2").SetXValue("Registros: "+count+" de "+total);

  //Genero la Lista de IDS
  var lst=Ctrl("LIST_2");   

  lst.IDs=new Array();
  for (var cur=RS.FirstChild(); cur!=null; cur=cur.Next())
  	lst.IDs.push(cur.GetAttr("id"));

	lst.ResetSQL();
}

//Habilita los Botones
function EnabledButtons()
{ 
	var cur,f;
	if (Ctrl("LIST").GetXValue()=="" || Ctrl("LIST").TotalRow<=0)
	{
		CtrlEnabled("SHOW"  ,false);
		CtrlEnabled("ADD"   ,true );
		CtrlEnabled("EDIT"  ,false);
		CtrlEnabled("DELETE",false);
		CtrlEnabled("ADMIN" ,false);

		CtrlEnabled("S_DEL"    ,false);
		CtrlEnabled("S_DEL_ALL",Ctrl("LIST").TotalRow!=0?true:false);

		//Buscar que botones estan habilitados siempre
		for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
		{
			f=cur.GetAttrInt("flag");
			CtrlEnabled(cur.GetAttr("name"), f==2);
		}
	} else                           
	if (Ctrl("LIST").GetSelectAttrValue("lock")!="")
	{
		CtrlEnabled("SHOW"  ,true );
		CtrlEnabled("ADD"   ,true );
		CtrlEnabled("EDIT"  ,false);
		CtrlEnabled("DELETE",false); 
		CtrlEnabled("ADMIN" ,GetProxy().Admin());

		CtrlEnabled("S_DEL"    ,false);
		CtrlEnabled("S_DEL_ALL",false);

		//Buscar que botones estan habilitados si esta bloqueado
		for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
		{
			f=cur.GetAttrInt("flag");
			CtrlEnabled(cur.GetAttr("name"), f==1);
		}
	} else
	{                 
		CtrlEnabled("SHOW"  ,true);
		CtrlEnabled("ADD"   ,true);
		CtrlEnabled("EDIT"  ,true);
		CtrlEnabled("DELETE",true); 
		CtrlEnabled("ADMIN" ,GetProxy().Admin());

		CtrlEnabled("S_DEL"    ,Ctrl("PERS").CountRow()>0?true:false);
		CtrlEnabled("S_DEL_ALL",true);

		//Habilitar todos los botones
		for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
			CtrlEnabled(cur.GetAttr("name"), true);
	}             

	CtrlEnabled("S_ADD"    ,Ctrl("ETTYS").CountRow()>0?true:false); 
	CtrlEnabled("S_ADD_ALL",Ctrl("LIST_2").TotalRow>0?true:false);
}

function InternalRefresh()
{
	LoadList();             
	EnabledButtons();
}

function OnRefresh()
{                         
	NomadTimeout("InternalRefresh();", 200, "Cargando la lista...");
}

function ReplaceResource(recID)
{
	var recValue=Ctrl("main").getResource(recID);
	recValue=Replace(recValue,"#RESOURCE-LIST#"  ,CFG.GetAttr("RESOURCE-LIST"  ));
	recValue=Replace(recValue,"#RESOURCE-ID#"    ,CFG.GetAttr("RESOURCE-ID"    ));
	recValue=Replace(recValue,"#RESOURCE-PARENT#",CFG.GetAttr("RESOURCE-PARENT"));
	recValue=Replace(recValue,"#RESOURCE-OBJECT#",CFG.GetAttr("RESOURCE-OBJECT"));

	Ctrl("main").setResource(recValue, recID);
}

///////////////////////////////////////////////////////////////////////////////          
//EVENTOS
function OnLoad()
{               
	//Cargo la Configuracion
	CFG   =new NomadXML(Ctrl("main").getResource("QRY_CFG"));
	CHLCFG=new NomadXML(Ctrl("main").getResource("QRY_CHILD"));

	//Modifico los Recursos
	ReplaceResource("QRY_IDS");
	ReplaceResource("QRY_IDS_LIST");
	ReplaceResource("QRY_IDS_METHOD");
	ReplaceResource("QRY_IDS_PARENT");

	//Actualizo el Titulo
	if ((CFG.GetAttr("RESOURCE-PARENT")!="") && (Ctrl("PARENT").GetXValue()!=""))
	{
		if (TIT==null)
			TIT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_IDS_PARENT"), '<PARAM IDS="'+Ctrl("PARENT").GetXValue()+'"/>');

		if (TIT!=null) TIT=TIT.FirstChild();
		if (TIT!=null && TIT.GetAttr("descr")!="")
			Ctrl("PAR").SetXValue(" ("+TIT.GetAttr("descr")+")");
	}

	//Cargo la Lista   
	OnRefresh();
}

function OnActivate()
{                
	//Cargo la Configuracion
	Ctrl("BUSCAR").SetFocus();
}

function OnOrder()
{
	Ctrl("ORDER").SetXValue((Ctrl("LIST").OrderMode=="ASC"?"+":"-")+Ctrl("LIST").OrderBy);
	OnRefresh();
}

function OnOrder2()
{
	Ctrl("ORDER_2").SetXValue((Ctrl("LIST_2").OrderMode=="ASC"?"+":"-")+Ctrl("LIST_2").OrderBy);
	OnRefresh();
}

function UnMarkAll()
{
	Ctrl("ETTYS").DelAllRow();
	OnRefresh();
}
function UnMarkPerAll()
{
	Ctrl("PERS").DelAllRow();
	OnRefresh();
}

function MarkAll()
{
	Ctrl("ETTYS").DelAllRow();

  var lst=Ctrl("LIST_2");   
  for (var t=0; t<lst.IDs.length; t++)
  	Ctrl("ETTYS").AddRow().SetAttr("ID", lst.IDs[t]);

	OnRefresh();
}                     
function MarkPerAll()
{
	Ctrl("PERS").DelAllRow();

  var lst=Ctrl("LIST");   
  for (var t=0; t<lst.IDs.length; t++)
  	Ctrl("PERS").AddRow().SetAttr("ID", lst.IDs[t]);

	OnRefresh();
}                     

function DelAll()
{	  
  AddList();
}

function AddAll()
{
	var lista=new Array();

  var lst=Ctrl("LIST_2");   
  for (var t=0; t<lst.IDs.length; t++)
  	lista.push(lst.IDs[t]);

  ValidarList(lista);
}

function AddSelect()
{
	var siAdd=new Array();               
	var lista=new Array();

  var lst=Ctrl("ETTYS");   
  for (var t=0; t<lst.CountRow(); t++)
  	siAdd[lst.GetRow(t).GetAttr("ID")]=1;

  var lst=Ctrl("LIST");   
  for (var t=0; t<lst.IDs.length; t++)
  	siAdd[lst.IDs[t]]=1;

	for (key in siAdd)  	
  	lista.push(key);

  ValidarList(lista);
}

function DelSelect()
{
	var noAdd=new Array();               
	var lista=new Array();

  var lst=Ctrl("PERS");   
  for (var t=0; t<lst.CountRow(); t++)
  	noAdd[lst.GetRow(t).GetAttr("ID")]=1;

  var lst=Ctrl("LIST");   
  for (var t=0; t<lst.IDs.length; t++)
  	if (noAdd[lst.IDs[t]]?false:true)
  		lista.push(lst.IDs[t]);

  AddList(lista);
}

function ValidarList(lista)
{
	var ids = "";
  	var xmlParam = new NomadXML("PARAM");
	xmlParam.SetAttr("PARENT",Ctrl("PARENT").GetXValue()); 
     //xmlParam.SetAttr("LIST","\""+lista.join("\",\"")+"\"");
	 for (var t=0; t<lista.length; t++)
     {
         ids += "<ROW id='"+lista[t]+"' />";
     } 
    xmlParam.AddText(ids);

	var nSQL = GetProxy().SQLService();
	var objResult= nSQL.GetOBJ(Ctrl("main").getResource("QRY_VALIDAR_IDS"), xmlParam.ToString());

	if (objResult.valid == "1")	
		AddList(lista);
	else
		alert("Se seleccionaron legajos que ya cumplen este rol en el organigrama");
}

function AddList(lista)
{
	var xmlParam = new NomadXML("PARAM");
	xmlParam.SetAttr("PARENT",Ctrl("PARENT").GetXValue());
	if (lista != null) xmlParam.SetAttr("LIST",lista.join(","));

	openNewFlowWait("NucleusWF.Base.Definicion.Organigramas.ENTIDAD_ESTR.MAIN.STD.flow","CHANGE",xmlParam.ToString(),new FlowResult(),"L");	
}


////////////////////////////////////////////////////////////////////////////////////////////////
function FlowResult()
{
	this.processResult = function(xml)
	{
		//Cargo la Lista   
		OnRefresh();
	}
}

///////////////////////////////////////////////////////////////////////////////          
//ACCIONES
function RegShow()    
{ 
	if (Ctrl("SHOW")?false:true) return false;
	if (!Ctrl("SHOW").GetEnabled()) return false;    

	Ctrl("main").DoEvent("SHOW"  ); 
	return true; 
}
function RegAdd()     
{ 
	if (Ctrl("ADD")?false:true) return false;
	if (!Ctrl("ADD").GetEnabled()) return false;    

	Ctrl("main").DoEvent("ADD"   ); 
	return true; 
}
function RegEdit()    
{ 
	if (Ctrl("EDIT")?false:true) return false;
	if (!Ctrl("EDIT").GetEnabled()) return false;    

	Ctrl("main").DoEvent("EDIT"  ); 
	return true; 
}
function RegDelete()  
{ 
	if (Ctrl("DELETE")?false:true) return false;
	if (!Ctrl("DELETE").GetEnabled()) return false;    
	if (!confirm("¿Esta seguro que quiere eliminar el Registro?")) return false;

	Ctrl("main").DoEvent("DELETE"); 
	return true; 
}
function RegAdmin()   
{ 
	if (Ctrl("ADMIN")?false:true) return false;
	if (!Ctrl("ADMIN").GetEnabled()) return false;            

	Ctrl("main").DoEvent("ADMIN" ); 
	return true; 
}

function ActionBACK() 
{
	if (Ctrl("BACK")?false:true) return false;
	if (!Ctrl("BACK").GetEnabled()) return false;    
	if (!confirm("¿Esta seguro que quiere Salir de la Pantalla?")) return false;

	Ctrl("main").DoEvent("BACK"  ); 
	return true; 
}
function ActionNEXT() 
{ 
	if (Ctrl("NEXT")?false:true) return false;
	if (!Ctrl("NEXT").GetEnabled()) return false;    

	Ctrl("main").DoEvent("NEXT"  ); 
	return true; 
}
function ActionPREV() 
{ 
	if (Ctrl("PREV")?false:true) return false;
	if (!Ctrl("PREV").GetEnabled()) return false;    

	Ctrl("main").DoEvent("PREV"  ); 
	return true; 
}
function ActionEND() 
{ 
	if (Ctrl("END")?false:true) return false;
	if (!Ctrl("END").GetEnabled()) return false;    
	if (!confirm("¿Esta seguro que quiere Terminar la Operacion?")) return false;

	Ctrl("main").DoEvent("BACK"  ); 
	return true; 
}
function DependCall(obj)
{
	if (Ctrl("LIST").GetXValue()=="") return;

	var flowId=CHLCFG.FindElement2("CHILD","name",obj.ID()).GetAttr("flow");

	if (flowId.indexOf(":")>=0)
		appendFormInMain(flowId.split(":")[0], flowId.split(":")[1], '<DATA PARENT="'+Ctrl("LIST").GetXValue()+'" />');
	else
		appendFormInMain(flowId              , "LIST"              , '<DATA PARENT="'+Ctrl("LIST").GetXValue()+'" />');
}
